    public class NotificationTests
    {
        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var now = System.DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New Student created",
                CreatedAt = now,
                CreatedBy = "admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New Student created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Notification_IsRead_CanBeSetToTrue()
        {
            var readTime = System.DateTime.Now;
            var notification = new Notification
            {
                IsRead = true,
                ReadAt = readTime
            };

            Assert.True(notification.IsRead);
            Assert.Equal(readTime, notification.ReadAt);
        }
    }

    public class EntityOperationTests
    {
        [Theory]
        [InlineData(EntityOperation.CREATE, "CREATE")]
        [InlineData(EntityOperation.UPDATE, "UPDATE")]
        [InlineData(EntityOperation.DELETE, "DELETE")]
        public void EntityOperation_HasCorrectStringRepresentation(EntityOperation operation, string expectedName)
        {
            Assert.Equal(expectedName, operation.ToString());
        }
    }
}
