namespace ContosoUniversity.Tests.Models
{
    public class EnrollmentTests
    {
        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment();
            Assert.Null(enrollment.Grade);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Enrollment_Grade_CanBeSetToAnyValue(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Properties_SetCorrectly()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 100,
                StudentID = 5,
                Grade = Grade.B
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(100, enrollment.CourseID);
            Assert.Equal(5, enrollment.StudentID);
            Assert.Equal(Grade.B, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_NavigationProperties_CanBeSet()
        {
            var course = new Course { Title = "Math" };
            var student = new Student { LastName = "Doe" };
            var enrollment = new Enrollment { Course = course, Student = student };

            Assert.Same(course, enrollment.Course);
            Assert.Same(student, enrollment.Student);
        }
    }
}

