    {
        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5
            };

            Assert.Equal(1, department.DepartmentID);
            Assert.Equal("Engineering", department.Name);
            Assert.Equal(350000m, department.Budget);
            Assert.Equal(new DateTime(2007, 9, 1), department.StartDate);
            Assert.Equal(5, department.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var department = new Department { InstructorID = null };
            Assert.Null(department.InstructorID);
        }

        [Fact]
        public void Department_RowVersion_CanBeSet()
        {
            var rowVersion = new byte[] { 0, 0, 0, 1 };
            var department = new Department { RowVersion = rowVersion };
            Assert.Equal(rowVersion, department.RowVersion);
        }

        [Fact]
        public void Department_NavigationProperties_CanBeInitialized()
        {
            var instructor = new Instructor { LastName = "Smith" };
            var department = new Department
            {
                Administrator = instructor,
                Courses = new List<Course> { new Course { Title = "Calculus" } }
            };

            Assert.Same(instructor, department.Administrator);
            Assert.Single(department.Courses);
        }
    }
}

