+            // Drain any leftover notifications from other tests (shared static queue)
+            while (_sut.ReceiveNotification() != null) { }
+        }
+
+        public void Dispose()
+        {
+            _sut.Dispose();
+        }
+
+        [Fact]
+        public void SendNotification_WithDisplayName_EnqueuesNotification()
+        {
+            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");
+
+            var result = _sut.ReceiveNotification();
+
+            Assert.NotNull(result);
+            Assert.Equal("Student", result.EntityType);
+            Assert.Equal("1", result.EntityId);
+            Assert.Equal("CREATE", result.Operation);
+            Assert.Contains("John Doe", result.Message);
+            Assert.Equal("admin", result.CreatedBy);
+            Assert.False(result.IsRead);
+        }
+
+        [Fact]
+        public void SendNotification_WithoutDisplayName_UsesEntityId()
+        {
+            _sut.SendNotification("Course", "42", EntityOperation.UPDATE, "teacher");
+
+            var result = _sut.ReceiveNotification();
+
+            Assert.NotNull(result);
+            Assert.Equal("Course", result.EntityType);
+            Assert.Equal("42", result.EntityId);
+            Assert.Equal("UPDATE", result.Operation);
+            Assert.Contains("ID: 42", result.Message);
+            Assert.Equal("teacher", result.CreatedBy);
+        }
+
+        [Fact]
+        public void SendNotification_WithNullUserName_DefaultsToSystem()
+        {
+            _sut.SendNotification("Department", "1", EntityOperation.DELETE);
+
+            var result = _sut.ReceiveNotification();
+
+            Assert.NotNull(result);
+            Assert.Equal("System", result.CreatedBy);
+        }
+
+        [Theory]
+        [InlineData(EntityOperation.CREATE, "has been created")]
+        [InlineData(EntityOperation.UPDATE, "has been updated")]
+        [InlineData(EntityOperation.DELETE, "has been deleted")]
+        public void SendNotification_GeneratesCorrectMessage(EntityOperation operation, string expectedFragment)
+        {
+            _sut.SendNotification("Student", "1", "Test Student", operation, "admin");
+
+            var result = _sut.ReceiveNotification();
+
+            Assert.Contains(expectedFragment, result.Message);
+        }
+
+        [Fact]
+        public void ReceiveNotification_ReturnsNull_WhenQueueEmpty()
+        {
+            var result = _sut.ReceiveNotification();
+            Assert.Null(result);
+        }
+
+        [Fact]
+        public void ReceiveNotification_ReturnsFIFOOrder()
+        {
+            _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
+            _sut.SendNotification("Student", "2", "Second", EntityOperation.CREATE);
+
+            var first = _sut.ReceiveNotification();
+            var second = _sut.ReceiveNotification();
+
+            Assert.Equal("1", first.EntityId);
+            Assert.Equal("2", second.EntityId);
+        }
+
+        [Fact]
+        public void ReceiveNotification_RemovesFromQueue()
+        {
+            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
+
+            var first = _sut.ReceiveNotification();
+            var second = _sut.ReceiveNotification();
+
+            Assert.NotNull(first);
+            Assert.Null(second);
+        }
+
+        [Fact]
+        public void MarkAsRead_DoesNotThrow()
+        {
+            // MarkAsRead is a no-op for in-memory implementation but should not throw
+            var ex = Record.Exception(() => _sut.MarkAsRead(999));
+            Assert.Null(ex);
+        }
+
+        [Fact]
+        public void SendNotification_CreatedAt_IsSetToCurrentTime()
+        {
+            var before = DateTime.Now.AddSeconds(-1);
+            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
+            var after = DateTime.Now.AddSeconds(1);
+
+            var result = _sut.ReceiveNotification();
+
+            Assert.InRange(result.CreatedAt, before, after);
+        }
+
+        [Fact]
+        public void Dispose_DoesNotThrow()
+        {
+            var service = new NotificationService();
+            var ex = Record.Exception(() => service.Dispose());
+            Assert.Null(ex);
+        }
+    }
+}
