using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_CanBeCreated()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context);
        }

        [Fact]
        public void SchoolContext_HasStudentsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Students);
        }

        [Fact]
        public void SchoolContext_HasCoursesDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Courses);
        }

        [Fact]
        public void SchoolContext_HasEnrollmentsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Enrollments);
        }

        [Fact]
        public void SchoolContext_HasDepartmentsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Departments);
        }

        [Fact]
        public void SchoolContext_HasInstructorsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Instructors);
        }

        [Fact]
        public void SchoolContext_HasNotificationsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Notifications);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            using var context = TestDbContextFactory.Create();
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.Today
            };

            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();
            Assert.Equal("Test", retrieved.LastName);
            Assert.Equal("User", retrieved.FirstMidName);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveDepartment()
        {
            using var context = TestDbContextFactory.Create();
            var dept = new Department
            {
                Name = "TestDept",
                Budget = 100000m,
                StartDate = DateTime.Today
            };

            context.Departments.Add(dept);
            context.SaveChanges();

            var retrieved = context.Departments.First();
            Assert.Equal("TestDept", retrieved.Name);
        }

        [Fact]
        public void SchoolContext_CourseAssignment_HasCompositeKey()
        {
            using var context = TestDbContextFactory.Create();

            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Today
            };
            context.Instructors.Add(instructor);

            var dept = new Department
            {
                Name = "Math",
                Budget = 50000m,
                StartDate = DateTime.Today
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 1001,
                Title = "Algebra",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var assignment = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            };
            context.CourseAssignments.Add(assignment);
            context.SaveChanges();

            var retrieved = context.CourseAssignments.First();
            Assert.Equal(instructor.ID, retrieved.InstructorID);
            Assert.Equal(course.CourseID, retrieved.CourseID);
        }
    }
}

