using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<string> { "a", "b" };
            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<string> { "a", "b" };
            // 10 items, page size 3 → ceil(10/3) = 4 pages
            var list = new PaginatedList<string>(items, 10, 1, 3);

            Assert.Equal(4, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 3, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_WhenNotOnFirstPage()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenOnLastPage()
        {
            // 10 items, page size 5 → 2 pages, on page 2
            var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
        {
            // 10 items, page size 5 → 2 pages, on page 1
            var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var page = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(5, page.Count);
            Assert.Equal(6, page[0]); // Items 6-10
            Assert.Equal(10, page[4]);
            Assert.Equal(2, page.PageIndex);
            Assert.Equal(4, page.TotalPages);
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 3);

            Assert.Equal(3, page.Count);
            Assert.Equal(1, page[0]);
            Assert.Equal(3, page[2]);
        }

        [Fact]
        public void Create_LastPage_ReturnRemainingItems()
        {
            var source = Enumerable.Range(1, 7).AsQueryable();

            // Page size 3 → pages: [1,2,3], [4,5,6], [7]
            var page = PaginatedList<int>.Create(source, 3, 3);

            Assert.Single(page);
            Assert.Equal(7, page[0]);
        }

        [Theory]
        [InlineData(1, 10, 1)]   // 1 item, size 10 → 1 page
        [InlineData(10, 10, 1)]  // 10 items, size 10 → 1 page
        [InlineData(11, 10, 2)]  // 11 items, size 10 → 2 pages
        [InlineData(0, 10, 0)]   // 0 items, size 10 → 0 pages
        public void TotalPages_CalculatesCorrectly(int count, int pageSize, int expectedPages)
        {
            var list = new PaginatedList<string>(new List<string>(), count, 1, pageSize);
            Assert.Equal(expectedPages, list.TotalPages);
        }
    }
}

