{"file_text": "using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Instructor SeedInstructor(string lastName = "Smith", string firstName = "John")
        {
            var instructor = new Instructor
            {
                LastName = lastName,
                FirstMidName = firstName,
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
            return instructor;
        }

        private Department SeedDepartment(string name = "TestDept")
        {
            var dept = new Department
            {
                Name = name,
                Budget = 100000m,
                StartDate = DateTime.Today
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        private Course SeedCourse(int courseId, string title = "TestCourse", Department dept = null)
        {
            if (dept == null)
                dept = SeedDepartment();
            var course = new Course
            {
                CourseID = courseId,
                Title = title,
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();
            return course;
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            SeedInstructor();

            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.Single(model.Instructors);
        }

        [Fact]
        public void Index_OrdersByLastName()
        {
            SeedInstructor("Zeta");
            SeedInstructor("Alpha");

            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            var instructors = model.Instructors.ToList();
            Assert.Equal("Alpha", instructors[0].LastName);
            Assert.Equal("Zeta", instructors[1].LastName);
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var dept = SeedDepartment();
            var course = SeedCourse(5001, "TestCourse", dept);
            var instructor = SeedInstructor();

            var assignment = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            };
            _context.CourseAssignments.Add(assignment);
            _context.SaveChanges();

            var result = _controller.Index(instructor.ID, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_NoId_CoursesIsNull()
        {
            SeedInstructor();

            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.Null(model.Courses);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = SeedInstructor("DetailMe");

            var result = _controller.Details(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("DetailMe", model.LastName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsViewResult_WithInstructor()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_POST_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_ValidInstructor_AddsToDatabase()
        {
            var instructor = new Instructor
            {
                LastName = "Created",
                FirstMidName = "Newly",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            _controller.Create(instructor, null);

            Assert.Single(_context.Instructors);
            Assert.Equal("Created", _context.Instructors.First().LastName);
        }

        [Fact]
        public void Create_POST_WithSelectedCourses_AddsCourseAssignments()
        {
            var dept = SeedDepartment();
            var course = SeedCourse(6001, "AssignedCourse", dept);

            var instructor = new Instructor
            {
                LastName = "WithCourses",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };

            var result = _controller.Create(instructor, new[] { course.CourseID.ToString() });

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);

            var saved = _context.Instructors.First(i => i.LastName == "WithCourses");
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.Single(assignments);
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = SeedInstructor("DeleteMe");

            var result = _controller.Delete(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("DeleteMe", model.LastName);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_RemovesInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "ToDelete",
                FirstMidName = "Test",
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(instructor.ID);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Empty(_context.Instructors);
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            var instructor = new Instructor
            {
                LastName = "Admin",
                FirstMidName = "Dept",
                HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var dept = new Department
            {
                Name = "TestDept",
                Budget = 50000m,
                StartDate = DateTime.Today,
                InstructorID = instructor.ID
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }

        #endregion
    }
}
