using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Student SeedStudent(string lastName = "Doe", string firstName = "Jane", DateTime? enrollmentDate = null)
        {
            var student = new Student
            {
                LastName = lastName,
                FirstMidName = firstName,
                EnrollmentDate = enrollmentDate ?? DateTime.Today
            };
            _context.Students.Add(student);
            _context.SaveChanges();
            return student;
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithStudents()
        {
            SeedStudent("Alpha");
            SeedStudent("Beta");

            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            SeedStudent("Zeta");
            SeedStudent("Alpha");

            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alpha", model[0].LastName);
            Assert.Equal("Zeta", model[1].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            SeedStudent("Alpha");
            SeedStudent("Zeta");

            var result = _controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Zeta", model[0].LastName);
            Assert.Equal("Alpha", model[1].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            SeedStudent("A", enrollmentDate: new DateTime(2022, 1, 1));
            SeedStudent("B", enrollmentDate: new DateTime(2020, 1, 1));

            var result = _controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(new DateTime(2020, 1, 1), model[0].EnrollmentDate);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            SeedStudent("A", enrollmentDate: new DateTime(2020, 1, 1));
            SeedStudent("B", enrollmentDate: new DateTime(2022, 1, 1));

            var result = _controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(new DateTime(2022, 1, 1), model[0].EnrollmentDate);
        }

        [Fact]
        public void Index_SearchString_FiltersStudentsByLastName()
        {
            SeedStudent("Alexander");
            SeedStudent("Smith");

            var result = _controller.Index(null, null, "Alex", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_FiltersStudentsByFirstName()
        {
            SeedStudent("Doe", "Jane");
            SeedStudent("Doe", "John");

            var result = _controller.Index(null, null, "Jane", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Jane", model[0].FirstMidName);
        }

        [Fact]
        public void Index_NewSearchString_ResetsPageToOne()
        {
            var result = _controller.Index(null, null, "test", 5);

            // When searchString is not null, page should be reset to 1
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            SeedStudent("KeepMe");
            SeedStudent("FilterOut");

            // First call with search string
            var result = _controller.Index(null, "KeepMe", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            var result = _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_WhenSortOrderIsDate_ViewBagDateSortParmIsDateDesc()
        {
            _controller.Index("Date", null, null, null);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var student = SeedStudent("Smith");

            var result = _controller.Details(student.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Smith", model.LastName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsViewResult_WithDefaultDate()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_ValidStudent_AddsToDatabase()
        {
            var student = new Student
            {
                LastName = "Created",
                FirstMidName = "Newly",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.Single(_context.Students);
            Assert.Equal("Created", _context.Students.First().LastName);
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student { EnrollmentDate = new DateTime(2023, 9, 1) };

            var result = _controller.Create(student);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_POST_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ErrorCount > 0);
        }

        [Fact]
        public void Create_POST_DateBefore1753_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithStudent()
        {
            var student = SeedStudent("EditMe");

            var result = _controller.Edit(student.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("EditMe", model.LastName);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_POST_ValidStudent_RedirectsToIndex()
        {
            var student = SeedStudent("Original");
            // Detach tracked entity so we can attach the edited one
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var edited = new Student
            {
                ID = student.ID,
                LastName = "Updated",
                FirstMidName = "Name",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Edit(edited);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Edit(student);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_POST_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ErrorCount > 0);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithStudent()
        {
            var student = SeedStudent("DeleteMe");

            var result = _controller.Delete(student.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("DeleteMe", model.LastName);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_RemovesStudent_RedirectsToIndex()
        {
            var student = SeedStudent("ToDelete");

            var result = _controller.DeleteConfirmed(student.ID);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Empty(_context.Students);
        }

        #endregion
    }
}

