            {
                CourseID = 2002,
                Title = "Database Course",
                Credits = 4,
                DepartmentID = dept.DepartmentID
            };

            _controller.Create(course, null);

            var saved = _context.Courses.Find(2002);
            Assert.NotNull(saved);
            Assert.Equal("Database Course", saved.Title);
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            SeedDepartment();
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 3001, Credits = 3 };

            var result = _controller.Create(course, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_POST_WithValidImage_SetsImagePath()
        {
            var dept = SeedDepartment();
            var course = new Course
            {
                CourseID = 3002,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.jpg");
            mockFile.Setup(f => f.Length).Returns(1024);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _controller.Create(course, mockFile.Object);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            var saved = _context.Courses.Find(3002);
            Assert.NotNull(saved.TeachingMaterialImagePath);
            Assert.StartsWith("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_POST_WithInvalidImageExtension_ReturnsView()
        {
            var dept = SeedDepartment();
            var course = new Course
            {
                CourseID = 3003,
                Title = "Bad Image Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.exe");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_WithOversizedImage_ReturnsView()
        {
            var dept = SeedDepartment();
            var course = new Course
            {
                CourseID = 3004,
                Title = "Large Image Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("large.jpg");
            mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

