using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Instructor SeedInstructor(string lastName = "Instructor")
        {
            var instructor = new Instructor
            {
                LastName = lastName,
                FirstMidName = "Test",
                HireDate = DateTime.Today
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
            return instructor;
        }

        private Department SeedDepartment(string name = "TestDept", Instructor admin = null)
        {
            var dept = new Department
            {
                Name = name,
                Budget = 100000m,
                StartDate = DateTime.Today,
                InstructorID = admin?.ID
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithDepartments()
        {
            SeedDepartment("Math");
            SeedDepartment("English");

            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Index_ReturnsEmptyList_WhenNoDepartments()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(viewResult.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var dept = SeedDepartment("Physics");

            var result = _controller.Details(dept.DepartmentID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("Physics", model.Name);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsViewResult()
        {
            var result = _controller.Create();
            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_POST_ValidDepartment_RedirectsToIndex()
        {
            var instructor = SeedInstructor();
            var dept = new Department
            {
                Name = "NewDept",
                Budget = 50000m,
                StartDate = DateTime.Today,
                InstructorID = instructor.ID
            };

            var result = _controller.Create(dept);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_ValidDepartment_AddsToDatabase()
        {
            var dept = new Department
            {
                Name = "Created",
                Budget = 75000m,
                StartDate = DateTime.Today
            };

            _controller.Create(dept);

            Assert.Single(_context.Departments);
            Assert.Equal("Created", _context.Departments.First().Name);
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department();

            var result = _controller.Create(dept);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithDepartment()
        {
            var dept = SeedDepartment("EditMe");

            var result = _controller.Edit(dept.DepartmentID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("EditMe", model.Name);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_POST_ValidDepartment_RedirectsToIndex()
        {
            var dept = SeedDepartment("Original");
            _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var edited = new Department
            {
                DepartmentID = dept.DepartmentID,
                Name = "Updated",
                Budget = 200000m,
                StartDate = DateTime.Today,
                RowVersion = dept.RowVersion
            };

            var result = _controller.Edit(edited);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            SeedInstructor();
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department { DepartmentID = 1 };

            var result = _controller.Edit(dept);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithDepartment()
        {
            var dept = SeedDepartment("DeleteMe");

            var result = _controller.Delete(dept.DepartmentID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("DeleteMe", model.Name);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_RemovesDepartment_RedirectsToIndex()
        {
            var dept = SeedDepartment("ToDelete");

            var result = _controller.DeleteConfirmed(dept.DepartmentID);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Null(_context.Departments.Find(dept.DepartmentID));
        }

        #endregion
    }
}

